const input = $input.first();
const raw = ($json.tool_input && typeof $json.tool_input === 'object') ? $json.tool_input : $json;
const message = String(raw.message || raw.media_caption || '').trim();
const buttonId = String(raw.button_id || '').trim();
const sourceType = String(raw.source_type || (buttonId ? 'button' : 'text')).trim() || 'text';
return [{
  json: {
    ...raw,
    chat_id: String(raw.chat_id || ''),
    message,
    button_id: buttonId,
    source_type: sourceType,
    media_id: String(raw.media_id || ''),
    media_mime_type: String(raw.media_mime_type || ''),
    media_filename: String(raw.media_filename || ''),
    media_caption: String(raw.media_caption || ''),
    store_id: raw.store_id || null,
    test_file_base64: String(raw.test_file_base64 || ''),
    test_file_name: String(raw.test_file_name || raw.media_filename || ''),
    test_file_mime_type: String(raw.test_file_mime_type || raw.media_mime_type || ''),
    test_sheet_rows: Array.isArray(raw.test_sheet_rows) ? raw.test_sheet_rows : [],
    test_mode: raw.test_mode === true,
    bulk_mode: String(raw.bulk_mode || ''),
    export_url: String(raw.export_url || ''),
    source_ref: String(raw.source_ref || ''),
    job_id: String(raw.job_id || ''),
  },
  binary: input?.binary || {},
}];

const d = $('Normalize Intake').first().json || {};
const message = String(d.message || '').trim();
const buttonId = String(d.button_id || '');
const sourceType = String(d.source_type || 'text');
const sheetMatch = message.match(/https?:\/\/docs\.google\.com\/spreadsheets\/d\/([a-zA-Z0-9-_]+)/i);
let action = 'prompt';
if (buttonId.startsWith('owner_bulk_apply__')) action = 'apply';
else if (buttonId.startsWith('owner_bulk_cancel__')) action = 'cancel';
else if (sourceType === 'document' || sourceType === 'image') action = 'start';
else if (sheetMatch || (Array.isArray(d.test_sheet_rows) && d.test_sheet_rows.length)) action = 'start';
const gidMatch = message.match(/[?#&]gid=([0-9]+)/i);
const spreadsheetId = sheetMatch ? sheetMatch[1] : '';
const gid = gidMatch ? gidMatch[1] : '0';
const jobId = d.job_id || ('bulk_' + Date.now() + '_' + Math.random().toString(36).slice(2, 8));
const reportToken = Math.random().toString(36).slice(2, 12);
return [{
  json: {
    ...d,
    action,
    job_id: action === 'start' ? jobId : String(buttonId.replace(/^owner_bulk_(?:apply|cancel)__/, '') || d.job_id || ''),
    report_token: reportToken,
    export_url: d.export_url || (spreadsheetId ? ('https://docs.google.com/spreadsheets/d/' + spreadsheetId + '/export?format=csv&gid=' + gid) : ''),
    source_ref: d.source_ref || (sheetMatch ? message : d.source_ref || ''),
    import_kind: sheetMatch || d.test_sheet_rows.length ? 'google_sheet' : (sourceType === 'document' || sourceType === 'image' ? 'file_upload' : d.bulk_mode || 'unknown'),
  },
  binary: $binary,
}];

const d = $('Decide Intake').first().json || {};
return [{
  json: {
    chat_id: d.chat_id || '',
    message_type: 'text',
    body_text: 'Bulk inventory onboarding accepts XLS, XLSX, or CSV files, plus public Google Sheets links. I will stage the rows, clean duplicates, and send a review summary before anything is saved. JPG, PNG, and PDF are accepted for medium imports only.',
    test_mode: d.test_mode === true,
  },
}];

